def _fromutc(self, dt):

    # 检查输入的日期时间对象是否带有时区信息
    if dt.tzinfo is None:
        raise ValueError("dt must be a timezone-aware datetime object")

    # 获取当前时区的UTC偏移量
    utc_offset = self.utcoffset(dt)

    # 计算新的日期时间
    new_dt = dt - utc_offset

    # 检查是否存在歧义
    if new_dt in self._ambiguous_dates:
        # 处理歧义情况
        if self._is_first_occurrence(new_dt):
            return new_dt.replace(tzinfo=self)
        else:
            raise ValueError("Ambiguous datetime detected")

    return new_dt.replace(tzinfo=self)

def _fromutc(self, dt):

    # 检查输入的日期时间对象是否带有时区信息
    if dt.tzinfo is None:
        raise ValueError("dt must be a timezone-aware datetime object")

    # 将输入的日期时间转换为 UTC 时间
    utc_dt = dt.astimezone(self.utc)

    # 计算在新时区的日期时间
    new_dt = utc_dt.astimezone(self)

    # 检查是否存在歧义
    if new_dt.dst() != timedelta(0):
        # 处理歧义情况
        if new_dt < self.fold_start:
            return new_dt.replace(fold=0)  # 第一个实例
        else:
            return new_dt.replace(fold=1)  # 第二个实例

    return new_dt

def _fromutc(self, dt):

    # 检查输入的日期时间对象是否带有时区信息
    if dt.tzinfo is None:
        raise ValueError("dt must be a timezone-aware datetime object")

    # 将输入的日期时间转换为 UTC 时间
    utc_dt = dt.astimezone(self.utc)

    # 计算在新时区的日期时间
    new_tz_dt = utc_dt.astimezone(self)

    # 检查是否存在歧义
    if new_tz_dt.dst() != timedelta(0):
        # 处理歧义情况
        if new_tz_dt < self.fold_start:
            new_tz_dt = new_tz_dt.replace(fold=0)
        else:
            new_tz_dt = new_tz_dt.replace(fold=1)

    return new_tz_dt

def normalized(self):

    total_days = int(self.days) + int(self.hours // 24)
    total_hours = int(self.hours % 24)
    total_minutes = int(self.minutes) + int(self.seconds // 60)
    total_seconds = int(self.seconds % 60)

    return relativedelta(days=total_days, hours=total_hours, minutes=total_minutes, seconds=total_seconds)

