import socket

def is_local(host):

    local_hosts = {'localhost', '127.0.0.1'}
    try:
        # 获取本地 IP 地址
        local_ip = socket.gethostbyname(socket.gethostname())
        local_hosts.add(local_ip)
    except socket.error:
        pass

    # 获取 host 的 IP 地址
    try:
        host_ip = socket.gethostbyname(host)
    except socket.error:
        return False

    return host_ip in local_hosts

