from typing import Optional, Set
from rdflib import Graph, URIRef

def find_roots(
    graph: Graph, prop: URIRef, roots: Optional[Set["Node"]] = None
) -> Set["Node"]:
    if roots is None:
        roots = set()

    all_nodes = set(graph.subjects(prop, None))
    child_nodes = set(graph.objects(None, prop))

    for node in all_nodes:
        if node not in child_nodes:
            roots.add(node)

    return roots

def find_roots(
    graph: "Graph", prop: "URIRef", roots: Optional[Set["Node"]] = None
) -> Set["Node"]:

    if roots is None:
        roots = set()

    all_children = {child for child, _, _ in graph.triples((None, prop, None))}
    all_parents = {parent for _, _, parent in graph.triples((None, prop, None))}

    # 根节点是没有父节点的节点
    root_candidates = all_children - all_parents

    roots.update(root_candidates)
    return roots

